const items = $input.all();
const fullText = items.map(i => i.json.text || '').join(' ');

const regulatoryKeywords = [
  'data storage', 'surveillance', 'personal data', 'privacy', 'consent',
  'data retention', 'data processing', 'security', 'encryption', 'access control',
  'data transfer', 'third party', 'user rights', 'notification', 'breach',
  'monitoring', 'collection', 'sharing', 'deletion', 'anonymization'
];

const foundKeywords = regulatoryKeywords.filter(kw =>
  fullText.toLowerCase().includes(kw.toLowerCase())
);

const searchQuery = foundKeywords.length > 0
  ? foundKeywords.join(', ')
  : 'regulatory compliance data privacy security';

return [{
  json: {
    policyText: fullText,
    searchQuery: searchQuery,
    foundKeywords: foundKeywords,
    fileName: items[0] && items[0].binary ? Object.keys(items[0].binary)[0] : 'policy_draft',
    timestamp: new Date().toISOString()
  }
}];

const items = $input.all();
const policyData = $('Extract Keywords for Vector Search').first().json;

const regulationChunks = items
  .filter(i => i.json.pageContent || i.json.text || i.json.content)
  .map(function(i, idx) {
    const content = i.json.pageContent || i.json.text || i.json.content || JSON.stringify(i.json);
    return '[Regulation Excerpt ' + (idx + 1) + ']\n' + content;
  })
  .join('\n\n---\n\n');

const context = regulationChunks || 'No specific regulations retrieved. Apply general GDPR and data protection principles.';

const prompt = 'You are an expert Legal Compliance Officer specializing in data protection law, GDPR, and municipal regulatory codes.\n\n' +
  'TASK: Review the provided policy draft against the retrieved regulatory context below. Identify every clause or section that contradicts, violates, or is non-compliant with the regulations.\n\n' +
  'RETRIEVED REGULATORY CONTEXT:\n' + context + '\n\n' +
  'POLICY DRAFT TO REVIEW:\n' + policyData.policyText + '\n\n' +
  'INSTRUCTIONS:\n' +
  '1. Analyze each section of the policy draft against the regulatory context.\n' +
  '2. For each non-compliant clause found, provide:\n' +
  '   - CLAUSE: Quote the exact non-compliant text from the draft\n' +
  '   - REGULATION VIOLATED: Name the specific regulation/article breached\n' +
  '   - ISSUE: Explain why it is non-compliant\n' +
  '   - RECOMMENDATION: Suggest corrective action\n' +
  '3. Provide an overall COMPLIANCE SCORE (0-100%) and RISK LEVEL (Low/Medium/High/Critical).\n' +
  '4. Summarize all findings in a structured COMPLIANCE REPORT.\n\n' +
  'FORMAT YOUR RESPONSE AS:\n' +
  '## COMPLIANCE REPORT\n' +
  '**Document Reviewed:** [filename]\n' +
  '**Review Date:** [date]\n' +
  '**Overall Compliance Score:** [X%]\n' +
  '**Risk Level:** [Low/Medium/High/Critical]\n\n' +
  '## NON-COMPLIANT CLAUSES\n' +
  '[List each violation with CLAUSE, REGULATION VIOLATED, ISSUE, RECOMMENDATION]\n\n' +
  '## COMPLIANT SECTIONS\n' +
  '[List sections that are compliant]\n\n' +
  '## EXECUTIVE SUMMARY\n' +
  '[Brief summary for management]';

return [{
  json: {
    policyText: policyData.policyText,
    searchQuery: policyData.searchQuery,
    foundKeywords: policyData.foundKeywords,
    fileName: policyData.fileName,
    timestamp: policyData.timestamp,
    regulatoryContext: context,
    prompt: prompt
  }
}];

const analysisResult = $input.first().json;
const contextData = $('Format Retrieved Regulations').first().json;

const reportText = analysisResult.text || analysisResult.response || analysisResult.output || 'Analysis could not be generated.';

const scoreMatch = reportText.match(/Compliance Score[:\s]+([\d]+)%/i);
const riskMatch = reportText.match(/Risk Level[:\s]+(Low|Medium|High|Critical)/i);
const complianceScore = scoreMatch ? scoreMatch[1] : 'N/A';
const riskLevel = riskMatch ? riskMatch[1] : 'Unknown';

const violationMatches = reportText.match(/CLAUSE:/gi) || [];
const violationCount = violationMatches.length;

const summary = reportText.length > 500 ? reportText.substring(0, 500) + '...' : reportText;

return [{
  json: {
    reportDate: contextData.timestamp,
    fileName: contextData.fileName,
    searchQuery: contextData.searchQuery,
    foundKeywords: Array.isArray(contextData.foundKeywords) ? contextData.foundKeywords.join(', ') : '',
    complianceScore: complianceScore,
    riskLevel: riskLevel,
    violationCount: violationCount,
    fullReport: reportText,
    reportSummary: summary,
    status: violationCount > 0 ? 'NON-COMPLIANT' : 'COMPLIANT'
  }
}];
